// mm/src/components/ui/PackageSelector.js
import React from 'react';

const DEFAULT_PACKAGES = [
  {
    id: 'basic',
    name: 'Basic Package',
    price: 49,
    tagline: 'Essential files for self-publishing',
    features: [
      'Print PDF (PDF/X-1a compliant)',
      'EPUB3 for digital distribution',
      'Basic metadata JSON',
      'Email delivery',
    ],
    popular: false,
  },
  {
    id: 'standard',
    name: 'Standard Package',
    price: 99,
    tagline: 'Complete publishing toolkit',
    features: [
      'Everything in Basic',
      'Multi-platform optimization',
      'Enhanced metadata with keywords',
      'Platform submission guidelines',
      'Priority email support',
    ],
    popular: true,
  },
  {
    id: 'premium',
    name: 'Premium Package',
    price: 199,
    tagline: 'Professional publishing suite',
    features: [
      'Everything in Standard',
      'Professional cover suggestions',
      'Marketing copy templates',
      'ISBN registration assistance',
      'Distribution strategy guide',
      'White-glove setup support',
    ],
    popular: false,
  },
];

const Check = () => (
  <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-emerald-50 text-emerald-600 border border-emerald-200">
    ✓
  </span>
);

const PackageCard = ({ pkg, selected, onSelect }) => {
  return (
    <button
      type="button"
      onClick={() => onSelect(pkg.id)}
      className={[
        'text-left w-full rounded-xl border bg-white p-6 transition shadow-sm',
        selected ? 'border-blue-600 ring-2 ring-blue-100' : 'border-slate-200 hover:border-slate-300',
      ].join(' ')}
    >
      <div className="flex items-start justify-between">
        <div>
          <div className="text-lg font-semibold text-slate-900">{pkg.name}</div>
          <div className="mt-2 text-4xl font-bold text-blue-600">${pkg.price}</div>
          <div className="mt-2 text-sm text-slate-500">{pkg.tagline}</div>
        </div>

        {pkg.popular ? (
          <div className="px-3 py-1 rounded-full text-xs font-semibold bg-blue-600 text-white">
            Most Popular
          </div>
        ) : null}
      </div>

      <ul className="mt-6 space-y-3">
        {pkg.features.map((f) => (
          <li key={f} className="flex items-start gap-3 text-sm text-slate-700">
            <Check />
            <span>{f}</span>
          </li>
        ))}
      </ul>
    </button>
  );
};

export default function PackageSelector({
  value,
  onChange,
  packages = DEFAULT_PACKAGES,
  className = '',
}) {
  return (
    <div className={className}>
      <h2 className="text-2xl font-semibold text-slate-900">Choose Your Package</h2>

      <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-6">
        {packages.map((pkg) => (
          <PackageCard
            key={pkg.id}
            pkg={pkg}
            selected={value === pkg.id}
            onSelect={(id) => onChange?.(id)}
          />
        ))}
      </div>
    </div>
  );
}
